"use client";

import { useEffect } from "react";
import { supabase } from "@/lib/supabase";

export default function Home() {

  useEffect(() => {

    async function loadSpots() {

      const { data, error } = await supabase
        .from("spots")
        .select("*");

      console.log("spots:", data);
      console.log("error:", error);

    }

    loadSpots();

  }, []);

  return (
    <main>
      <h1>Car Event MAP</h1>
      <p>Supabase test</p>
    </main>
  );
}